// Some portions generated by Codex
package org.eclipse.rdf4j.benchmark.rio.util;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Method;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class ThemeDataSetNTriplesExporterTest {

	@Test
	void runExportsEveryThemeIntoSingleNTriplesFile(@TempDir Path tempDir) throws Exception {
		Path outputFile = tempDir.resolve("nested/themes.nt");
		List<String> expectedLines = new ArrayList<>();

		Class<?> exporter = Class.forName("org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetNTriplesExporter");
		Class<?> emitterType = Arrays.stream(exporter.getDeclaredClasses())
				.filter(candidate -> candidate.getSimpleName().equals("ThemeEmitter"))
				.findFirst()
				.orElseThrow();
		Method run = exporter.getDeclaredMethod("run", String[].class, emitterType);
		run.setAccessible(true);
		Object emitter = java.lang.reflect.Proxy.newProxyInstance(
				exporter.getClassLoader(),
				new Class<?>[] { emitterType },
				(proxy, method, args) -> {
					Theme theme = (Theme) args[0];
					org.eclipse.rdf4j.rio.RDFHandler handler = (org.eclipse.rdf4j.rio.RDFHandler) args[1];
					Statement statement = SimpleValueFactory.getInstance()
							.createStatement(
									SimpleValueFactory.getInstance()
											.createIRI("http://example.com/export/" + theme.name().toLowerCase()),
									RDF.TYPE,
									SimpleValueFactory.getInstance()
											.createIRI("http://example.com/type/" + theme.name().toLowerCase()));
					expectedLines.add(toNTriples(statement));
					handler.startRDF();
					handler.handleNamespace("ignored", "http://example.com/ignored/");
					handler.handleComment("ignored");
					handler.handleStatement(statement);
					handler.endRDF();
					return null;
				});
		run.invoke(null, new String[] { outputFile.toString() }, emitter);

		assertEquals(expectedLines, Files.readAllLines(outputFile));
		assertEquals(Theme.values().length, expectedLines.size());
	}

	private static String toNTriples(Statement statement) {
		return "<" + statement.getSubject().stringValue() + "> "
				+ "<" + statement.getPredicate().stringValue() + "> "
				+ "<" + statement.getObject().stringValue() + "> .";
	}
}
